#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int X1,Y1,X2,Y2; scanf("%d %d %d %d",&X1,&Y1,&X2,&Y2);
        int sum1 = X1 + Y1;
        int sum2 = X2 + Y2;
        int ans = sum1 < sum2 ? sum1 : sum2;
        printf("%d\n", ans);
    }
    return 0;
}

